import React, { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';

const SearchResults = () => {
  const [allTours, setAllTours] = useState([]);
  const [tours, setTours] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchParams] = useSearchParams();

  const filterTours = (allTours) => {
    let filtered = [...allTours];
    const decodeParam = (param) => decodeURIComponent(param || '');

    const country = decodeParam(searchParams.get('country'));
    const departure = decodeParam(searchParams.get('departure'));

    if (country) {
      filtered = filtered.filter(tour => tour.country === country);
    }

    if (departure) {
      filtered = filtered.filter(tour => tour.departureCity === departure);
    }

    return filtered;
  };

  useEffect(() => {
    console.log('📦 Загружаем /api/tours.json...');
    
    fetch('/api/tours.json')
      .then(res => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json();
      })
      .then(data => {
        console.log('✅ Загружено:', data.length, 'туров');
        setAllTours(data);
        setLoading(false);
      })
      .catch(err => {
        console.error('❌ /api/tours.json:', err);
        
        // МОК данные (работает всегда)
        const mockTours = [
          {id:1, title:"Grand Emir Hotel ★★★", country:"Турция", city:"Стамбул", departureCity:"Москва", price:49728, nights:"6-14", dates:"15 фев - 24 фев", stars:3},
          {id:2, title:"Rixos Premium Tekirova ★★★★★", country:"Турция", city:"Кемер", departureCity:"Москва", price:125430, nights:"7-11", dates:"20 фев - 1 мар", stars:5},
          {id:3, title:"Jasmine Palace Beach Resort ★★★★", country:"Египет", city:"Хургада", departureCity:"СПб", price:78450, nights:"7-10", dates:"18 фев - 28 фев", stars:4},
          {id:4, title:"Hilton Sharjah ★★★★", country:"ОАЭ", city:"Шарджа", departureCity:"Москва", price:156780, nights:"6-14", dates:"22 фев - 5 мар", stars:4},
          {id:7, title:"Coral Beach Resort ★★★★", country:"Египет", city:"Шарм-эль-Шейх", departureCity:"Екатеринбург", price:69230, nights:"7-12", dates:"16 фев - 26 фев", stars:4}
        ];
        
        console.log('🔧 МОК данные:', mockTours.length, 'туров');
        setAllTours(mockTours);
        setLoading(false);
      });
  }, []);

  useEffect(() => {
    if (allTours.length > 0) {
      const filtered = filterTours(allTours);
      setTours(filtered);
    }
  }, [searchParams, allTours]);

  if (loading) {
    return (
      <div style={{margin: "0 auto", width: "1296px", padding: '40px', textAlign: 'center'}}>
        Загрузка туров...
      </div>
    );
  }

  return (
    <div style={{margin: "0 auto", width: "1296px", padding: '20px'}}>
      {/* Только счетчик — без лишней инфы */}
      <div style={{
        padding: '15px', 
        background: '#f8f9fa', 
        borderRadius: '6px',
        marginBottom: '20px',
        fontSize: '14px',
        textAlign: 'center'
      }}>
        <strong>Найдено туров: {tours.length}</strong>
      </div>

      {tours.length === 0 ? (
        <div style={{padding: '60px 20px', textAlign: 'center', color: '#666'}}>
          <h3>❌ Туры не найдены</h3>
          <p><strong>Текущие фильтры:</strong></p>
          <ul style={{textAlign: 'left', display: 'inline-block', fontSize: '14px'}}>
            <li>Страна: {decodeURIComponent(searchParams.get('country') || 'любая')}</li>
            <li>Вылет: {decodeURIComponent(searchParams.get('departure') || 'любой')}</li>
          </ul>
          <p style={{fontSize: '14px', marginTop: '20px'}}>
            <strong>Попробуйте:</strong><br/>
            Турция ← Москва | Египет ← СПб
          </p>
        </div>
      ) : (
        tours.map(tour => (
          <div key={tour.id} style={{
            border: '1px solid #ddd', 
            borderRadius: '12px', 
            padding: '20px', 
            marginBottom: '20px',
            background: 'white',
            boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
          }}>
            <div style={{display: 'flex', gap: '20px'}}>
              <div style={{
                width: '200px', 
                height: '140px', 
                background: `linear-gradient(45deg, #c50076, #ff6b9d)`,
                borderRadius: '8px',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                color: 'white', fontSize: '32px'
              }}>
                🏨
              </div>
              <div style={{flex: 1}}>
                <h3 style={{margin: '0 0 8px 0', color: '#333'}}>
                  {tour.title}
                </h3>
                <div style={{color: '#666', marginBottom: '8px'}}>
                  📍 {tour.city}, {tour.country}
                </div>
                <div style={{color: '#666', marginBottom: '8px'}}>
                  ✈️ Вылет из: {tour.departureCity}
                </div>
                <div style={{color: '#666', marginBottom: '12px'}}>
                  📅 {tour.dates} | {tour.nights} ночей
                </div>
                <div style={{fontSize: '28px', fontWeight: 'bold', color: '#c50076', marginBottom: '12px'}}>
                  {tour.price.toLocaleString()} ₽
                </div>
                <Link 
                  to={`/tour/${tour.id}`} 
                  style={{
                    display: 'inline-block', padding: '12px 24px',
                    background: '#c50076', color: 'white',
                    textDecoration: 'none', borderRadius: '6px',
                    fontWeight: '500'
                  }}
                >
                  Подробнее →
                </Link>
              </div>
            </div>
          </div>
        ))
      )}
    </div>
  );
};

export default SearchResults;
